    val cost = edge(2)
    graph.putIfAbsent(u, List())
    graph(u) = graph(u) :+ (v, cost)
  }

  import scala.collection.mutable.PriorityQueue
  class MaxHeap(val heap: scala.collection.mutable.ListBuffer[(Long, Long, Long)]) {
    def push(value: (Long, Long, Long)): Unit = {
      heap += value
      heap.sortWith((a, b) => a._2 > b._2)
    }

    def pop: (Long, Long, Long) = {
      if (heap.isEmpty) throw new NoSuchElementException("Heap is empty")
      val result = heap.head
      heap = heap.tail
      result
    }

    def isEmpty: Boolean = heap.isEmpty
  }

  val pq = new MaxHeap(scala.collection.mutable.ListBuffer[(Long, Long, Long)]())
  pq.push((0, 0, 0))

  val bestMin = scala.collection.mutable.HashMap[Long, Long]()
  bestMin.put(0, 0)

  val totalCost = scala.collection.mutable.HashMap[Long, Long]()
  totalCost.put(0, 0)

  while (!pq.isEmpty) {
    val (currentNode, currentMin, currentTotal) = pq.pop()
    val currentTotalVal = totalCost(currentNode)

    if (currentNode == n - 1) {
      return currentMin
    }

    if (bestMin(currentNode) > currentMin) {
      continue
    }

    graph.get(currentNode) match {
      case Some(neighbors) =>
        for (neighbor <- neighbors) {
