            val newMin = math.min(currentMin, edgeCost)
            if (newTotal <= k && newMin > bestMin.getOrElse(v, -1)) {
              bestMin.put(v, newMin)
              totalCost.put(v, newTotal)
              pq.push((v, newMin, newTotal))
            }
          }
        }
      case None =>
    }
  }

  -1
}
